"""RLM configuration management."""
from __future__ import annotations

from pathlib import Path
from typing import Any

from pydantic import Field
from pydantic_settings import BaseSettings, SettingsConfigDict


class RLMConfig(BaseSettings):
    """RLM runtime configuration."""

    model_config = SettingsConfigDict(
        env_prefix="RLM_",
        env_file=".env",
        env_file_encoding="utf-8",
        extra="ignore",
    )

    # Backend settings
    backend: str = "litellm"
    model: str = "gpt-4o-mini"
    temperature: float = 0.0

    # Environment settings
    environment: str = "local"
    docker_image: str = "python:3.11-slim"
    docker_cpus: float = 1.0
    docker_memory: str = "1g"

    # Limits
    max_depth: int = 4
    max_subcalls: int = 12
    token_budget: int = 8000
    tool_budget: int = 20
    timeout_seconds: int = 120

    # Logging
    log_dir: Path = Field(default_factory=lambda: Path("./logs"))
    verbose: bool = False

    # Snipara (optional)
    snipara_api_key: str | None = None
    snipara_project_slug: str | None = None

    @property
    def snipara_enabled(self) -> bool:
        return bool(self.snipara_api_key and self.snipara_project_slug)


def load_config(config_path: Path | None = None) -> RLMConfig:
    """Load configuration from file and environment."""
    if config_path and config_path.exists():
        import tomllib
        with open(config_path, "rb") as f:
            data = tomllib.load(f)
        return RLMConfig(**data.get("rlm", {}))
    return RLMConfig()
```
